/* Example: deterministic shard calculation (pseudocode) */

function shardForGuild(guildId, totalShards) {
  // guildId is a 64-bit snowflake; low bits are fairly distributed
  return (guildId >> 22) % totalShards; // shift off timestamp bits, mod by shard count
}

