/* Node.js minimal OpenTelemetry HTTP server + propagation example */
const { NodeTracerProvider } = require('@opentelemetry/sdk-trace-node');
const { registerInstrumentations } = require('@opentelemetry/instrumentation');
const { HttpInstrumentation } = require('@opentelemetry/instrumentation-http');
const { Resource } = require('@opentelemetry/resources');
const { SemanticResourceAttributes } = require('@opentelemetry/semantic-conventions');
const { SimpleSpanProcessor } = require('@opentelemetry/sdk-trace-base');
const { ConsoleSpanExporter } = require('@opentelemetry/sdk-trace-base');

const provider = new NodeTracerProvider({
  resource: new Resource({
    [SemanticResourceAttributes.SERVICE_NAME]: 'orders-service'
  })
});
provider.addSpanProcessor(new SimpleSpanProcessor(new ConsoleSpanExporter()));
provider.register();

registerInstrumentations({ instrumentations: [new HttpInstrumentation()] });

const http = require('http');
const tracer = provider.getTracer('example');

http.createServer((req, res) => {
  const span = tracer.startSpan('handle_request');
  // In a real app, inject context into outbound requests so downstream services
  // receive the traceparent header. Logs should include span.context().traceId.
  res.writeHead(200);
  res.end('ok');
  span.end();
}).listen(8080);
